(function initIndiaGeoSelects() {
    var states = Object.keys(window.INDIA_GEO).sort();

    function populateStateSelect(sel, savedState) {
        sel.innerHTML = '<option value="">— Select State —</option>';
        states.forEach(function(s) {
            var opt = document.createElement('option');
            opt.value = s;
            opt.textContent = s;
            if (s === savedState) opt.selected = true;
            sel.appendChild(opt);
        });
    }

    function populateDistrictSelect(distSel, stateName, savedDistrict) {
        distSel.innerHTML = '<option value="">— Select District —</option>';
        var districts = (window.INDIA_GEO[stateName] || []);
        districts.forEach(function(d) {
            var opt = document.createElement('option');
            opt.value = d;
            opt.textContent = d;
            if (d === savedDistrict) opt.selected = true;
            distSel.appendChild(opt);
        });
    }

    // Full form — permanent address
    var permState = document.getElementById('permStateSelect');
    var permDist  = document.getElementById('permDistrictSelect');
    if (permState && permDist) {
        var savedPermState    = permState.dataset.saved || '';
        var savedPermDistrict = permDist.dataset.saved  || '';
        populateStateSelect(permState, savedPermState);
        if (savedPermState) populateDistrictSelect(permDist, savedPermState, savedPermDistrict);

        permState.addEventListener('change', function () {
            populateDistrictSelect(permDist, this.value, '');
            if (typeof onPermAddressChange === 'function') onPermAddressChange();
        });
        permDist.addEventListener('change', function () {
            if (typeof onPermAddressChange === 'function') onPermAddressChange();
        });
    }

    // Quick form — permanent address
    var qPermState = document.getElementById('quickPermState');
    var qPermDist  = document.getElementById('quickPermDistrict');
    if (qPermState && qPermDist) {
        var savedQState    = qPermState.dataset.saved || '';
        var savedQDistrict = qPermDist.dataset.saved  || '';
        populateStateSelect(qPermState, savedQState);
        if (savedQState) populateDistrictSelect(qPermDist, savedQState, savedQDistrict);

        qPermState.addEventListener('change', function () {
            populateDistrictSelect(qPermDist, this.value, '');
        });
    }

    // Standalone state-only selects (Center, Channel Partner forms)
    ['centerStateSelect', 'partnerStateSelect'].forEach(function (id) {
        var sel = document.getElementById(id);
        if (!sel) return;
        populateStateSelect(sel, sel.dataset.saved || '');
    });
})();
</script>
